 11	import DefaultSelectHeader from '@components/common/TableView/DefaultSelectHeader';
 12	import type { GlobalActionToolbarProps } from '@components/common/utils/types';
 13	import { Td, Th } from '@patternfly/react-table';
 14	
 15	import type { RowProps, TableViewHeaderProps } from '../common/TableView/types';
 16	import { withTr } from '../common/TableView/withTr';
 17	
 18	import StandardPage, { type StandardPageProps } from './StandardPage';
 19	import type {
 20	  IdBasedSelectionProps,
 21	  WithHeaderSelectionProps,
 22	  WithRowSelectionProps,
 23	} from './types';
 24	
 25	const withRowSelection = <T,>({
 26	  canSelect,
 27	  CellMapper,
 28	  expandedIds,
 29	  selectedIds,
 30	  toggleExpandFor,
 31	  toggleSelectFor,
 32	  toId,
 33	}: WithRowSelectionProps<T> & {
 34	  selectedIds?: string[];
 35	  expandedIds?: string[];
 36	  toId?: (item: T) => string;
 37	}) => {
 38	  const Enhanced = (props: RowProps<T>) => {
 39	    const itemId = toId?.(props.resourceData) ?? '';
 40	    const isExpanded = expandedIds?.includes(itemId) ?? false;
 41	    const isSelected = selectedIds?.includes(itemId) ?? false;
 42	
 43	    return (
 44	      <>
 45	        {expandedIds !== undefined && (
 46	          <Td
 47	            expand={{
 48	              isExpanded,
 49	              onToggle: () => {
 50	                toggleExpandFor([props.resourceData]);
 51	              },
 52	              rowIndex: props.resourceIndex,
 53	            }}
 54	          />
 55	        )}
 56	        {selectedIds !== undefined && (
 57	          <Td
 58	            select={{
 59	              isDisabled: !canSelect?.(props.resourceData),
 60	              isSelected,
 61	              onSelect: () => {
 62	                toggleSelectFor([props.resourceData]);
 63	              },
 64	              rowIndex: props.resourceIndex,
 65	            }}
 66	          />
 67	        )}
 68	        {CellMapper && <CellMapper {...props} />}
 69	      </>
 70	    );
 71	  };
 72	
 73	  return Enhanced;
 74	};
 75	
 76	const withHeaderSelection = <T,>({ HeaderMapper, isExpanded }: WithHeaderSelectionProps<T>) => {
 77	  const Enhanced = ({ dataOnScreen, ...other }: TableViewHeaderProps<T>) => {
 78	    return (
 79	      <>
 80	        {isExpanded && <Th />}
 81	        {HeaderMapper && <HeaderMapper {...{ ...other, dataOnScreen }} />}
 82	      </>
 83	    );
 84	  };
 85	
 86	  return Enhanced;
 87	};
