 89	/**
 90	 * Adds ID based multi selection to StandardPage component.
 91	 * Contract:
 92	 * 1. IDs provided with toId() function are unique and constant in time
 93	 * 2. check box status at row level does not depend from other rows and  can be calculated from the item via canSelect() function
 94	 */
 95	const withIdBasedSelection = <T,>({
 96	  canSelect: initialCanSelect,
 97	  expandedIds: initialExpandedIds,
 98	  onExpand: initialOnExpand,
 99	  onSelect: initialOnSelect,
100	  selectedIds: initialSelectedIds,
101	  toId: initialToId,
102	}: IdBasedSelectionProps<T>) => {
103	  const Enhanced = (
104	    props: StandardPageProps<T> & {
105	      selectedIds?: string[];
106	      expandedIds?: string[];
107	      onSelect?: (selectedIds: string[]) => void;
108	      onExpand?: (expandedIds: string[]) => void;
109	      canSelect?: (item: T) => boolean;
110	      toId?: (item: T) => string;
111	    },
112	  ) => {
113	    const selectedIds = props.selectedIds ?? initialSelectedIds;
114	    const expandedIds = props.expandedIds ?? initialExpandedIds;
115	    const onSelect = props.onSelect ?? initialOnSelect;
116	    const onExpand = props.onExpand ?? initialOnExpand;
117	    const canSelect = props.canSelect ?? initialCanSelect;
118	    const toId = props.toId ?? initialToId;
119	
120	    const [internalSelectedIds, setInternalSelectedIds] = useState(selectedIds);
121	    const [internalExpandedIds, setInternalExpandedIds] = useState(expandedIds);
122	    const itemToId = useCallback((item: T) => (toId ? toId(item) : ''), [toId]);
123	
124	    useEffect(() => {
125	      setInternalSelectedIds(selectedIds);
126	    }, [selectedIds]);
127	
128	    useEffect(() => {
129	      setInternalExpandedIds(expandedIds);
130	    }, [expandedIds]);
131	
132	    const isExpanded = useMemo(
133	      () =>
134	        onExpand || internalExpandedIds
135	          ? (item: T) => internalExpandedIds?.includes(itemToId(item))
136	          : undefined,
137	      [onExpand, internalExpandedIds, itemToId],
138	    );
139	
140	    const toggleSelectFor = useCallback(
141	      (items: T[]) => {
142	        const ids = items.map(itemToId);
143	        const allSelected = ids.every((id) => internalSelectedIds?.includes(id));
144	        const newSelectedIds = [
145	          ...(internalSelectedIds ?? []).filter((it) => !ids.includes(it)),
146	          ...(allSelected ? [] : ids),
147	        ];
148	
149	        setInternalSelectedIds(newSelectedIds);
150	
151	        if (onSelect) {
152	          onSelect(newSelectedIds);
153	        }
154	      },
155	      [itemToId, internalSelectedIds, onSelect],
156	    );
157	
158	    const toggleExpandFor = useCallback(
159	      (items: T[]) => {
160	        const ids = items.map(itemToId);
161	        const allExpanded = ids.every((id) => internalExpandedIds?.includes(id));
162	        const newExpandedIds = [
163	          ...(internalExpandedIds ?? []).filter((it) => !ids.includes(it)),
164	          ...(allExpanded ? [] : ids),
165	        ];
166	
167	        setInternalExpandedIds(newExpandedIds);
168	        if (onExpand) {
169	          onExpand(newExpandedIds);
170	        }
171	      },
172	      [itemToId, internalExpandedIds, onExpand],
173	    );
174	
175	    const { CellMapper, ExpandedComponent, ...rest } = props;
176	
177	    const RowMapper = useMemo(() => {
178	      return withTr(
179	        withRowSelection({
180	          canSelect,
181	          CellMapper,
182	          expandedIds: internalExpandedIds,
183	          selectedIds: internalSelectedIds,
184	          toggleExpandFor,
185	          toggleSelectFor,
186	          toId,
187	        }),
188	        ExpandedComponent,
189	      );
190	    }, [
191	      ExpandedComponent,
192	      CellMapper,
193	      toggleExpandFor,
194	      toggleSelectFor,
195	      internalSelectedIds,
196	      internalExpandedIds,
197	      canSelect,
198	      toId,
199	    ]);
200	
201	    const HeaderMapper = useMemo(
202	      () =>
203	        withHeaderSelection({
204	          HeaderMapper: props.HeaderMapper ?? DefaultSelectHeader,
205	          isExpanded,
206	        }),
207	      [props.HeaderMapper, isExpanded],
208	    );
209	
210	    const onSelectCallback = useCallback(
211	      (ids: string[]) => {
212	        setInternalSelectedIds(ids);
213	        onSelect?.(ids);
214	      },
215	      [onSelect],
216	    );
217	
218	    return (
219	      <StandardPage
220	        {...rest}
221	        expandedIds={internalExpandedIds}
222	        selectedIds={internalSelectedIds}
223	        onSelect={onSelectCallback}
224	        toId={toId}
225	        RowMapper={RowMapper}
226	        HeaderMapper={HeaderMapper}
227	        GlobalActionToolbarItems={props.GlobalActionToolbarItems?.map(
228	          (Action: FC<GlobalActionToolbarProps<T>>) => {
229	            const ActionWithSelection = (actionProps: ComponentProps<typeof Action>) => (
230	              <Action {...actionProps} selectedIds={internalSelectedIds} />
231	            );
232	            ActionWithSelection.displayName = `${Action.displayName ?? 'Action'}WithSelection`;
233	
234	            return ActionWithSelection;
235	          },
236	        )}
237	      />
238	    );
239	  };
240	  Enhanced.displayName = 'StandardPageWithSelection';
241	  return Enhanced;
242	};
