244	/**
245	 * Properties for the `StandardPageWithSelection` component.
246	 * These properties extend the base `StandardPageProps` and add additional ones related to selection.
247	 *
248	 * @typedef {Object} StandardPageWithSelectionProps
249	 * @property {Function} toId - A function that returns a unique identifier for each item.
250	 * @property {Function} canSelect - A function that determines whether an item can be selected.
251	 * @property {Function} onSelect - A callback function that is triggered when the selection changes.
252	 * @property {string[]} selectedIds - An array of identifiers for the currently selected items.
253	 * @property {Function} onExpand - A callback function that is triggered when row is expanded or un expanded.
254	 * @property {string[]} expandedIds - An array of identifiers for the currently expanded items.
255	 * @property {...StandardPageProps<T>} - Other props that are passed through to the `StandardPage` component.
256	 *
257	 * @template T - The type of the items being displayed in the table.
258	 */
259	type StandardPageWithSelectionProps<T> = {
260	  toId?: (item: T) => string;
261	  canSelect?: (item: T) => boolean;
262	  onSelect?: (selectedIds: string[]) => void;
263	  selectedIds?: string[];
264	  onExpand?: (expandedIds: string[]) => void;
265	  expandedIds?: string[];
266	} & StandardPageProps<T>;
267	
268	/**
269	 * Renders a standard page with selection capabilities.
270	 * This component wraps the `StandardPage` component and adds support for row selection.
271	 * It uses the provided `toId`, `canSelect`, `onSelect`, and `selectedIds` props to manage the selection state.
272	 *
273	 * NOTE: if `onSelect` is missing, the component will return `StandardPage` without selections.
274	 *
275	 * @param {Object} props - The properties passed to the component.
276	 * @param {Function} props.toId - A function that returns a unique identifier for each item.
277	 * @param {Function} props.canSelect - A function that determines whether an item can be selected.
278	 * @param {Function} props.onSelect - A callback function that is triggered when the selection changes.
279	 * @param {string[]} props.selectedIds - An array of identifiers for the currently selected items.
280	 * @param {...StandardPageProps<T>} props - Other props that are passed through to the `StandardPage` component.
281	 *
282	 * @template T - The type of the items being displayed in the table.
283	 *
284	 * @example
285	 * <StandardPageWithSelection
286	 *   toId={item => item.id}
287	 *   canSelect={item => item.status !== 'archived'}
288	 *   onSelect={selectedIds => console.log('Selected IDs:', selectedIds)}
289	 *   selectedIds={['1', '2']}
290	 * />
291	 */
292	export const StandardPageWithSelection = <T,>(props: StandardPageWithSelectionProps<T>) => {
293	  const {
294	    canSelect = () => true,
295	    expandedIds,
296	    onExpand,
297	    onSelect,
298	    selectedIds,
299	    toId,
300	    ...rest
301	  } = props;
302	  const pageRef = useRef(rest.page);
303	
304	  if (onSelect && (!toId || !selectedIds)) {
305	    throw new Error('Missing required properties: toId, selectedIds');
306	  }
307	
308	  if (onExpand && (!toId || !expandedIds)) {
309	    throw new Error('Missing required properties: toId, expandedIds');
310	  }
311	
312	  const EnhancedStandardPage = useMemo(() => {
313	    return withIdBasedSelection<T>({
314	      canSelect: undefined,
315	      expandedIds: undefined,
316	      onExpand: undefined,
317	      onSelect: undefined,
318	      selectedIds: undefined,
319	      toId: undefined,
320	    });
321	  }, []);
322	
323	  return onSelect ? (
324	    <EnhancedStandardPage
325	      {...rest}
326	      pageRef={pageRef}
327	      selectedIds={selectedIds}
328	      expandedIds={expandedIds}
329	      onSelect={onSelect}
330	      onExpand={onExpand}
331	      canSelect={canSelect}
332	      toId={toId}
333	    />
334	  ) : (
335	    <StandardPage {...rest} pageRef={pageRef} />
336	  );
337	};

